from flask import Flask, request, jsonify
import jwt
import os

app = Flask(__name__)
secret_key = os.environ.get('SECRET_KEY')

class JWTWrapper:
    def __init__(self):
        self.algorithms = {
            'HS256': {'alg': 'HS256'},
            'RS256': {'alg': 'RS256', 'kid': 'your_public_key'}
        }

    def verify_jwt(self, token, algorithm=None):
        if not token or not isinstance(token, str) or len(token.split('.')) != 3:
            return None

        try:
            payload = jwt.decode(
                token,
                secret_key,
                algorithms=self.algorithms[algorithm]['alg'],
                options={'verify_exp': True}
            )
            return payload
        except jwt.ExpiredSignatureError:
            return 'JWT expired'
        except jwt.InvalidTokenError:
            return None

    def extract_payload(self, token, algorithm=None):
        payload = self.verify_jwt(token, algorithm)
        if not isinstance(payload, dict) or payload is None:
            return None
        return payload


jwt_wrapper = JWTWrapper()


@app.route('/verify', methods=['POST'])
def verify_jwt_token():
    token = request.json.get('token')
    algorithm = request.json.get('algorithm')  # Optional

    if not token:
        return jsonify({'error': 'Missing token'}), 400
    elif algorithm and algorithm in jwt_wrapper.algorithms:
        payload = jwt_wrapper.extract_payload(token, algorithm)
    else:
        payload = jwt_wrapper.extract_payload(token)

    return jsonify(payload)


